const raw = $json.output?.[0]?.content?.[0]?.text ?? $json.text ?? $json;

let expense;

if (typeof raw === 'string') {
  const cleaned = raw
    .replace(/^```json\s*/i, '')
    .replace(/```$/i, '')
    .trim();

  try {
    expense = JSON.parse(cleaned);
  } catch (error) {
    throw new Error(`Invalid JSON returned by the AI: ${error.message}`);
  }
} else {
  expense = raw;
}

return [{
  json: {
    ...expense,
    expense_id: $('Prepare Expense Data').first().json.expense_id,
    employee_email: $('Prepare Expense Data').first().json.employee_email,
    file_name: $('Prepare Expense Data').first().json.file_name,
    mime_type: $('Prepare Expense Data').first().json.mime_type,
    processed_at: $('Prepare Expense Data').first().json.processed_at,
  },
}];

